import{_ as i,o as e,c as a,ai as t}from"./chunks/framework.BZ-K7CQ_.js";const c=JSON.parse('{"title":"Rotating the Postgres password on an existing self-hosted install","description":"","frontmatter":{},"headers":[],"relativePath":"rotate-postgres-password.md","filePath":"rotate-postgres-password.md"}'),n={name:"rotate-postgres-password.md"};function h(l,s,o,r,d,p){return e(),a("div",null,[...s[0]||(s[0]=[t(`<h1 id="rotating-the-postgres-password-on-an-existing-self-hosted-install" tabindex="-1">Rotating the Postgres password on an existing self-hosted install <a class="header-anchor" href="#rotating-the-postgres-password-on-an-existing-self-hosted-install" aria-label="Permalink to “Rotating the Postgres password on an existing self-hosted install”">​</a></h1><p>Until version 3.10, <code>arcsecond hosting setup</code> wrote a default Postgres password (<code>arcsecond_docker</code>) into <code>.env</code>. New installs now generate a per-install random password automatically, but <strong>existing installs keep the original weak password until you rotate it manually</strong> — Postgres only reads <code>POSTGRES_PASSWORD</code> at first container boot to bootstrap the role, so changing the value in <code>.env</code> after the fact does nothing on its own.</p><p>This guide rotates the password in three coordinated places: the live database role, the <code>.env</code> file, and the running containers.</p><h2 id="_1-pick-a-new-password" tabindex="-1">1. Pick a new password <a class="header-anchor" href="#_1-pick-a-new-password" aria-label="Permalink to “1. Pick a new password”">​</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">NEW_PG_PASSWORD</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python3</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;import os, base64; print(base64.urlsafe_b64encode(os.urandom(32)).decode().rstrip(&#39;=&#39;))&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$NEW_PG_PASSWORD</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span></code></pre></div><p>Keep this in your shell session — you will paste it into two places.</p><h2 id="_2-change-the-password-in-the-live-db" tabindex="-1">2. Change the password in the live DB <a class="header-anchor" href="#_2-change-the-password-in-the-live-db" aria-label="Permalink to “2. Change the password in the live DB”">​</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> exec</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -it</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> arcsecond-db</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> psql</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -U</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> arcsecond_docker</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> arcsecond_docker</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;ALTER USER arcsecond_docker WITH PASSWORD &#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$NEW_PG_PASSWORD</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;;&quot;</span></span></code></pre></div><p>The role&#39;s password is now updated in Postgres. The backend container is holding open connections that authenticated under the old password — they will keep working until restart, which is fine; we restart in step 4.</p><h2 id="_3-update-env" tabindex="-1">3. Update <code>.env</code> <a class="header-anchor" href="#_3-update-env" aria-label="Permalink to “3. Update .env”">​</a></h2><p>Replace the <code>POSTGRES_PASSWORD=...</code> line in your <code>.env</code> (next to <code>docker-compose.yml</code>) with the new value. Keep the same <code>POSTGRES_USER</code> and <code>POSTGRES_DB</code> values — only the password changes.</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sed</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i.bak</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;s/^POSTGRES_PASSWORD=.*/POSTGRES_PASSWORD=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$NEW_PG_PASSWORD</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .env</span></span></code></pre></div><p>(macOS <code>sed</code> writes a <code>.env.bak</code> backup. Inspect, then delete the backup once you&#39;ve confirmed the rewrite worked.)</p><h2 id="_4-restart-the-stack" tabindex="-1">4. Restart the stack <a class="header-anchor" href="#_4-restart-the-stack" aria-label="Permalink to “4. Restart the stack”">​</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restart</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> backend</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> worker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> beat</span></span></code></pre></div><p>Backend, worker, and beat re-read <code>.env</code> and pick up the new password. The <code>db</code> container itself does <strong>not</strong> need a restart — its data was already updated in step 2, and a <code>db</code> restart would not re-read <code>POSTGRES_PASSWORD</code> anyway (it only does so on first init of an empty volume).</p><h2 id="_5-verify" tabindex="-1">5. Verify <a class="header-anchor" href="#_5-verify" aria-label="Permalink to “5. Verify”">​</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> logs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 50</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> backend</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;database&#39;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsS</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:8800/healthcheck/</span></span></code></pre></div><p>If <code>healthcheck/</code> returns 200, you&#39;re done.</p><h2 id="file-permissions" tabindex="-1">File permissions <a class="header-anchor" href="#file-permissions" aria-label="Permalink to “File permissions”">​</a></h2><p>While you&#39;re in <code>.env</code>, lock it down so other local users can&#39;t read it:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 600</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .env</span></span></code></pre></div><p>The file holds the Postgres password, the Django <code>SECRET_KEY</code>, the field encryption key, and the JWT signing keys. None of them are useful to an attacker on their own, but defense in depth is cheap.</p>`,23)])])}const g=i(n,[["render",h]]);export{c as __pageData,g as default};
